$k=$args[0];$e=if($args[1]){[Net.WebUtility]::UrlDecode($args[1])-split","}else{@()};$a=[Security.Cryptography.SHA256]::Create();Get-LocalUser|?{$_.Name-notin$e}|%{$r="$($_.Name.ToUpper())$k";$h=$a.ComputeHash([Text.Encoding]::UTF8.GetBytes($r));$p=-join($h|%{$_.ToString("x2")});$c=ConvertTo-SecureString $p.Substring(0,16) -A -Fo;Set-LocalUser -Na $_.Name -Password $c;echo "$($_.Name)"}
